use std::sync::{Arc, Mutex};

struct NotSendSync {
    data: String,
}

unsafe impl Send for NotSendSync {}
unsafe impl Sync for NotSendSync {}

fn main() {
    let not_send_sync = NotSendSync { data: "hello".to_string() };
    let shared = Arc::new(Mutex::new(not_send_sync));
    let handle = std::thread::spawn(move || {
        let mut lock = shared.lock().unwrap();
        println!("{}", lock.data);
    });
    handle.join().unwrap();
}

